import json

# Get all NYSE Arca ETFs
etf_result = locals()['var_functions.execute_python:22']
if isinstance(etf_result, str) and etf_result.endswith('.json'):
    with open(etf_result, 'r') as f:
        etf_info = json.load(f)
else:
    etf_info = etf_result

all_nyse_arca_etfs = etf_info['etfs']

# Check if any of the remaining potential high-value ETFs are in our list
remaining_candidates = ['DDM', 'SLV', 'CEF', 'LQD', 'IAU', 'SPXL', 'TNA', 'ERX', 'FAS']

candidates_available = []
for symbol in remaining_candidates:
    if symbol in all_nyse_arca_etfs:
        candidates_available.append(symbol)

print("__RESULT__:")
print(json.dumps({
    "total_etfs_to_check": len(all_nyse_arca_etfs),
    "remaining_candidates": candidates_available
}))

